CREATE TABLE assurance_contracts(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, version INTEGER NOT NULL, content TEXT NOT NULL, content_hash TEXT NOT NULL, active INTEGER NOT NULL DEFAULT 0, created_by TEXT NOT NULL REFERENCES users(id), created_at TEXT NOT NULL, UNIQUE(project_id,version));
CREATE TABLE pipeline_compilations(id TEXT PRIMARY KEY, pipeline_id TEXT NOT NULL REFERENCES pipelines(id) ON DELETE CASCADE, pipeline_version INTEGER NOT NULL, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, contract_id TEXT NOT NULL, contract_hash TEXT NOT NULL, plan TEXT NOT NULL, status TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE run_assurance_bindings(run_id TEXT PRIMARY KEY REFERENCES runs(id) ON DELETE CASCADE, compilation_id TEXT NOT NULL REFERENCES pipeline_compilations(id), contract_id TEXT NOT NULL, contract_version INTEGER NOT NULL, contract_hash TEXT NOT NULL, contract_snapshot TEXT NOT NULL, bound_at TEXT NOT NULL);
CREATE TABLE research_opportunities(id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, opportunity_type TEXT NOT NULL, title TEXT NOT NULL, description TEXT NOT NULL, source_nodes TEXT NOT NULL, rationale TEXT NOT NULL, novelty_scope TEXT NOT NULL, feasibility REAL NOT NULL, expected_impact REAL NOT NULL, required_capabilities TEXT NOT NULL, suggested_pipeline TEXT NOT NULL, uncertainty TEXT NOT NULL, risks TEXT NOT NULL, status TEXT NOT NULL, created_at TEXT NOT NULL);
